namespace sv_3815b843863e4d3580046ffcb20891ac.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public interface INotificationService
{
    Task<List<Notification>> GetNotificationsAsync();
    Task<List<Notification>> GetNewNotificationsSinceAsync(DateTime since);
}

public class NotificationService : INotificationService
{
    private int _nextId = 4;
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)),
        new(3, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-1)),
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        return Task.FromResult(_notifications.ToList());
    }

    public Task<List<Notification>> GetNewNotificationsSinceAsync(DateTime since)
    {
        // Simulate occasional new notifications
        if (Random.Shared.Next(3) == 0)
        {
            var id = _nextId++;
            var notification = new Notification(id, $"New alert #{id} arrived.", DateTime.UtcNow);
            _notifications.Add(notification);
        }

        var results = _notifications.Where(n => n.Timestamp > since).ToList();
        return Task.FromResult(results);
    }
}

