@page "/notifications"
@rendermode InteractiveServer
@using sv_3815b843863e4d3580046ffcb20891ac.Services
@inject INotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Notifications is not null)
    {
        <span class="badge bg-primary ms-2">@Notifications.Count</span>
    }
</h1>

@if (Notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (Notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in Notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? Notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not already restored from prerender state
        Notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never runs during prerender — safe to start polling
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        var lastCheck = Notifications?.MaxBy(n => n.Timestamp)?.Timestamp ?? DateTime.UtcNow;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var newNotifications = await NotificationService.GetNewNotificationsSinceAsync(lastCheck);
            if (newNotifications.Count > 0)
            {
                Notifications ??= new();
                Notifications.AddRange(newNotifications);
                lastCheck = newNotifications.Max(n => n.Timestamp);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

