         try
         {
             while (!cancellationToken.IsCancellationRequested)
             {
                 await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                 var newNotifications = await NotificationService.GetNewNotificationsSinceAsync(lastCheck);
                 if (newNotifications.Count > 0)
                 {
                     Items ??= new();
                     Items.AddRange(newNotifications);
                     lastCheck = newNotifications.Max(n => n.Timestamp);
                     await InvokeAsync(StateHasChanged);
                 }
             }
         }
         catch (TaskCanceledException)
         {
             // Expected when the component is disposed
         }
     }

     public void Dispose()
     {
         _cts?.Cancel();
         _cts?.Dispose();
     }
 }

